  answerIdentitySection,
  answerCoreBehaviorSection,
  answerSecuritySection,
  answerToolGuidanceSection,
  answerOrgContextSection,
  answerDotlightfastSection,    // <-- add after orgContext
  answerTemporalContextSection,
  answerStyleSection,
  answerCitationSection,
];
```

#### 4. Extend `buildAnswerSystemPrompt`

**File**: `apps/app/src/ai/prompts/system-prompt.ts`

Add `dotlightfast` to the options and pass it through:

```ts
interface AnswerPromptOptions {
  modelId?: string;
  org: {
    name: string;
    /** Cached .lightfast content */
    dotlightfast?: string;
  };
}

export function buildAnswerSystemPrompt(options: AnswerPromptOptions): string {
  const context = buildPromptContext({
    isAnonymous: false,
    userId: "system",
    activeTools: ["orgSearch"],
    features: {
      temporalContext: true,
      style: true,
      toolGuidance: true,
      userContext: true,
    },
    style: "formal",
    temporalContext: {
      currentTimestamp: new Date().toISOString(),
    },
    userContext: {
      org: {
        name: options.org.name,
        dotlightfast: options.org.dotlightfast,
        repos: [],
        integrations: [],
      },
    },
    modelId: options.modelId ?? "anthropic/claude-sonnet-4-5-20250929",
  });

  return buildPrompt(context, ANSWER_PROVIDERS);
}
```

#### 5. Fetch Cached Content in Answer Route

**File**: `apps/app/src/app/(api)/v1/answer/[...v]/route.ts`

Add a DB query to fetch the cached `.lightfast` content before building the system prompt. This applies to both `POST` and `GET` handlers.

Add import at the top:

```ts
import { db } from "@db/app/client";
import { orgContextConfigs } from "@db/app/schema";
import { and, eq } from "drizzle-orm";
```

In the `POST` handler, after fetching `clerkOrg` (line 47) and before `buildAnswerSystemPrompt` (line 60):

```ts
// Fetch cached .lightfast content
const [contextConfig] = await db
  .select({ content: orgContextConfigs.content })
  .from(orgContextConfigs)
  .where(
    and(
      eq(orgContextConfigs.clerkOrgId, authData.clerkOrgId),
      eq(orgContextConfigs.isActive, true)
    )
  )
  .limit(1);

