  answerStyleSection,
  answerCitationSection,
];
```

#### 4. Extend `buildAnswerSystemPrompt`

**File**: `apps/app/src/ai/prompts/system-prompt.ts`

Add `dotlightfast` to the options and pass it through:

```ts
interface AnswerPromptOptions {
  modelId?: string;
  org: {
    name: string;
    /** Cached .lightfast content */
    dotlightfast?: string;
  };
}

export function buildAnswerSystemPrompt(options: AnswerPromptOptions): string {
  const context = buildPromptContext({
    isAnonymous: false,
    userId: "system",
    activeTools: ["orgSearch"],
    features: {
      temporalContext: true,
      style: true,
      toolGuidance: true,
      userContext: true,
    },
    style: "formal",
    temporalContext: {
      currentTimestamp: new Date().toISOString(),
    },
    userContext: {
      org: {
        name: options.org.name,
        dotlightfast: options.org.dotlightfast,
        repos: [],
        integrations: [],
      },
    },
    modelId: options.modelId ?? "anthropic/claude-sonnet-4-5-20250929",
  });

  return buildPrompt(context, ANSWER_PROVIDERS);
}
```

#### 5. Fetch Cached Content in Answer Route

**File**: `apps/app/src/app/(api)/v1/answer/[...v]/route.ts`

Add a DB query to fetch the cached `.lightfast` content before building the system prompt. This applies to both `POST` and `GET` handlers.

Add import at the top:

```ts
import { db } from "@db/app/client";
import { orgContextConfigs } from "@db/app/schema";
import { and, eq } from "drizzle-orm";
```

In the `POST` handler, after fetching `clerkOrg` (line 47) and before `buildAnswerSystemPrompt` (line 60):

```ts
// Fetch cached .lightfast content
const [contextConfig] = await db
  .select({ content: orgContextConfigs.content })
  .from(orgContextConfigs)
  .where(
    and(
      eq(orgContextConfigs.clerkOrgId, authData.clerkOrgId),
      eq(orgContextConfigs.isActive, true)
    )
  )
  .limit(1);

const systemPrompt = buildAnswerSystemPrompt({
  org: {
    name: clerkOrg.name,
    dotlightfast: contextConfig?.content ?? undefined,
  },
  modelId: MODEL_ID,
});
```

Apply the same pattern in the `GET` handler (around line 153).

### Success Criteria:

#### Automated Verification:

- [ ] `pnpm typecheck` passes
- [ ] `pnpm check` passes
- [ ] `pnpm build:app` passes

#### Manual Verification:

- [ ] With an active context config containing README.md content, send a message to the Answer agent
- [ ] Inspect the system prompt (via logging or debugger) — `.lightfast` content appears under "ORG CONTEXT (.lightfast):"
- [ ] Without an active context config, the section is absent from the prompt
- [ ] Ask the Answer agent about org-specific information defined in `.lightfast` README.md — it should respond using that context

**Implementation Note**: After completing this phase and all automated verification passes, pause here for manual confirmation from the human that the manual testing was successful before proceeding to the next phase.

---

## Testing Strategy

### Unit Tests:

- `answerDotlightfastSection` — returns null when no content, returns section with content when present
- `buildAnswerSystemPrompt` — includes `.lightfast` content in output when provided

### Integration Tests:

- Context sync Inngest function — mock GitHub API response, verify DB update
- Activate procedure — mock `proxy.execute`, verify DB insert + content cached

### Manual Testing Steps:

1. Create a `.lightfast` repo on GitHub with a README.md
2. Connect it via Sources
3. Go to Settings > Context — verify detection
4. Activate — verify content cached in DB
5. Push a README.md change — verify auto-sync via Inngest
6. Chat with Answer agent — verify `.lightfast` context in responses
7. Deactivate — verify content no longer in prompt
8. Disconnect repo from Sources — verify cascade delete of context config

## Performance Considerations

- **DB query per Answer request**: The `orgContextConfigs` query adds one indexed read per Answer API call. This is negligible — single row by unique `clerkOrgId` index.
- **Token budget**: `.lightfast` content competes with other `high` priority sections for the 4000-token budget. Large README.md files may be truncated by the prompt builder. The `estimateTokens` function uses `content.length / 4` as an approximation.
- **Webhook throughput**: The `contextSync` Inngest function early-returns for all non-push events and for repos without active context configs. The two early-return checks (provider + eventType, then DB lookup) are fast and don't impact normal webhook processing.

## References

- Original research: `thoughts/shared/research/2026-04-04-dotlightfast-feature-design.md`
- GitHub API `get-file-contents`: `packages/app-providers/src/providers/github/api.ts:154-169`
- Existing usage pattern: `api/app/src/router/org/connections.ts:355-360` (`detectConfig`)
- Prompt engine types: `packages/prompt-engine/src/types.ts:60-103`
- Settings sub-page pattern: `apps/app/src/app/(app)/(org)/[slug]/(manage)/settings/api-keys/`
- Inngest function pattern: `api/platform/src/inngest/functions/ingest-delivery.ts`
- Token helpers: `api/platform/src/lib/token-helpers.ts:14-70`

